import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as d,e as i}from"./app-be253e4c.js";const r={},o=i('<h1 id="命令模式" tabindex="-1"><a class="header-anchor" href="#命令模式" aria-hidden="true">#</a> 命令模式</h1><p>命令模式<code>Command Pattern</code>是一种数据驱动的设计模式，其属于行为型模式，别名为动作<code>Action</code>模式或事务<code>Transaction</code> 模式，命令模式将请求以命令的形式包裹在对象中，并传给调用对象，调用对象寻找可以处理该命令的合适的对象，并把该命令传给相应的对象，该对象对请求排队或者记录请求日志，以及支持可撤销的操作。</p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>在软件设计中，我们经常需要向某些对象发送请求，但是并不知道请求的接收者是谁，也不知道被请求的操作是哪个，我们只需在程序运行时指定具体的请求接收者即可，此时，可以使用命令模式来进行设计，使得请求发送者与请求接收者消除彼此之间的耦合，让对象之间的调用关系更加灵活。命令模式可以对发送者和接收者完全解耦，发送者与接收者之间没有直接引用关系，发送请求的对象只需要知道如何发送请求，而不必知道如何完成请求。命令模式也可以用于实现基于事务的系统，一旦执行命令，便会继续保留命令的历史记录，如果最终命令成功执行，那么一切都很好，否则只需遍历历史记录并继续对所有已执行的命令执行撤消即可。</p><h3 id="优点" tabindex="-1"><a class="header-anchor" href="#优点" aria-hidden="true">#</a> 优点</h3><ul><li>降低系统的耦合度。</li><li>新的命令可以很容易地加入到系统中。</li><li>可以比较容易地设计一个命令队列和宏命令(组合命令)。</li><li>可以方便地实现对请求的Undo和Redo。</li></ul><h3 id="缺点" tabindex="-1"><a class="header-anchor" href="#缺点" aria-hidden="true">#</a> 缺点</h3><ul><li>使用命令模式可能会导致某些系统有过多的具体命令类。因为针对每一个命令都需要设计一个具体命令类，因此某些系统可能需要大量具体命令类，这将影响命令模式的使用。</li></ul><h3 id="适用环境" tabindex="-1"><a class="header-anchor" href="#适用环境" aria-hidden="true">#</a> 适用环境</h3><ul><li>系统需要将请求调用者和请求接收者解耦，使得调用者和接收者不直接交互。</li><li>系统需要在不同的时间指定请求、将请求排队和执行请求。</li><li>系统需要支持命令的撤销<code>Undo</code>操作和恢复<code>Redo</code>操作。</li><li>系统需要将一组操作组合在一起，即支持宏命令</li></ul><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2>',11),c=[o];function h(n,l){return a(),d("div",null,c)}const u=e(r,[["render",h],["__file","command-mode.html.vue"]]);export{u as default};
